INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES (1070036, "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", "", "", 1, 112611, 7, 1, 11, "", 10);
